public Set<ThreadMetadata> metadataForLocalThreads() {
    final Set<ThreadMetadata> threadMetadata = new HashSet<>();
    processStreamThread(thread -> {
        synchronized (thread.getStateLock()) {
            if (thread.state() != StreamThread.State.DEAD) {
